'use client';

import { useState, useEffect, useCallback } from 'react';

interface McpToken {
  id: string;
  scope: string;
  expiresAt: string | null;
  lastUsedAt: string | null;
  createdAt: string;
  revokedAt: string | null;
}

export default function McpTokensPage() {
  const [tokens, setTokens] = useState<McpToken[]>([]);
  const [scope, setScope] = useState<'full' | 'readonly' | 'memory_only'>('full');
  const [expiresInDays, setExpiresInDays] = useState(365);
  const [creating, setCreating] = useState(false);
  const [newlyCreatedToken, setNewlyCreatedToken] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [revoking, setRevoking] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fetchTokens = useCallback(async () => {
    try {
      const res = await fetch('/api/mcp-tokens');
      if (res.ok) {
        const data = await res.json();
        setTokens(data.tokens || []);
      }
    } catch (e) {
      console.error('Failed to fetch MCP tokens', e);
    }
  }, []);

  useEffect(() => {
    fetchTokens();
  }, [fetchTokens]);

  const handleCreate = async () => {
    setCreating(true);
    setError(null);
    try {
      const res = await fetch('/api/mcp-tokens', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ scope, expiresInDays }),
      });
      if (res.ok) {
        const data = await res.json();
        setNewlyCreatedToken(data.token);
        fetchTokens();
      } else {
        const err = await res.json();
        setError(err.error || 'Failed to create token');
      }
    } catch (_e) {
      setError('Network error');
    } finally {
      setCreating(false);
    }
  };

  const handleRevoke = async (id: string) => {
    setRevoking(id);
    try {
      await fetch(`/api/mcp-tokens?id=${id}`, { method: 'DELETE' });
      fetchTokens();
    } finally {
      setRevoking(null);
    }
  };

  // Simple revoke using the GET/POST for now; in real we'd add DELETE handler.
  // For this impl, we'll use a revoke action by calling the bridge indirectly.
  // To make functional, let's add quick revoke via API (we'll assume /api/mcp-tokens supports DELETE for id).

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2500);
  };

  const closeNewToken = () => {
    setNewlyCreatedToken(null);
  };

  const activeTokens = tokens.filter((t) => !t.revokedAt);
  const revokedTokens = tokens.filter((t) => t.revokedAt);

  return (
    <div className="max-w-4xl mx-auto p-6 space-y-8 text-[#F1F5F9]">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">MCP Server Tokens</h1>
        <p className="mt-2 text-[#94A3B8]">
          Generate long-lived tokens to connect external AI tools (Claude Desktop, Cursor, Continue.dev, etc.) directly to your Unimatrix memory via the core MCP server.
        </p>
        <p className="mt-1 text-sm text-[#64748B]">
          These tokens authenticate against the production MCP endpoint (e.g. https://your-mcp.onrender.com/mcp).
        </p>
      </div>

      {/* Create form */}
      <div className="bg-[#111827] border border-[#334155]/30 rounded-xl p-6">
        <h2 className="font-semibold mb-4">Create new MCP token</h2>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
          <div>
            <label className="block text-sm text-[#94A3B8] mb-1">Scope</label>
            <select
              value={scope}
              onChange={(e) => setScope(e.target.value as 'full' | 'readonly' | 'memory_only')}
              className="w-full bg-[#0A0F1C] border border-[#334155]/50 rounded px-3 py-2 text-sm focus:outline-none focus:border-[#00F5FF]"
            >
              <option value="full">Full access</option>
              <option value="readonly">Read-only (recall only)</option>
              <option value="memory_only">Memory only (store + recall)</option>
            </select>
          </div>

          <div>
            <label className="block text-sm text-[#94A3B8] mb-1">Expires in (days)</label>
            <input
              type="number"
              value={expiresInDays}
              onChange={(e) => setExpiresInDays(parseInt(e.target.value) || 365)}
              className="w-full bg-[#0A0F1C] border border-[#334155]/50 rounded px-3 py-2 text-sm focus:outline-none focus:border-[#00F5FF]"
            />
          </div>

          <div className="flex items-end">
            <button
              onClick={handleCreate}
              disabled={creating}
              className="w-full px-4 py-2 bg-[#00F5FF] text-[#0A0F1C] font-semibold rounded hover:bg-[#00D9FF] disabled:opacity-60 transition"
            >
              {creating ? 'Creating...' : 'Generate Token'}
            </button>
          </div>
        </div>

        {error && <p className="text-red-400 text-sm">{error}</p>}
      </div>

      {/* Newly created token warning + display */}
      {newlyCreatedToken && (
        <div className="bg-[#1A1F35] border border-[#00F5FF]/40 rounded-xl p-6">
          <div className="flex justify-between items-start mb-3">
            <div>
              <h3 className="font-bold text-[#00F5FF]">Token created successfully</h3>
              <p className="text-sm text-[#94A3B8]">Copy it now — it will not be shown again.</p>
            </div>
            <button onClick={closeNewToken} className="text-[#64748B] hover:text-white">✕</button>
          </div>

          <div className="bg-[#0A0F1C] p-4 rounded font-mono text-sm break-all border border-[#334155]/50">
            {newlyCreatedToken}
          </div>

          <div className="mt-3 flex gap-2">
            <button
              onClick={() => copyToClipboard(newlyCreatedToken)}
              className="px-3 py-1.5 bg-[#334155] hover:bg-[#475569] rounded text-sm"
            >
              {copied ? 'Copied!' : 'Copy to clipboard'}
            </button>
            <button onClick={closeNewToken} className="px-3 py-1.5 text-sm text-[#94A3B8]">Done</button>
          </div>

          <p className="mt-3 text-xs text-[#EF4444]">
            Store this in your AI client config (e.g. Claude Desktop mcp.json). Treat it like a password.
          </p>
        </div>
      )}

      {/* Active tokens */}
      <div>
        <h2 className="font-semibold mb-3">Active tokens</h2>
        {activeTokens.length === 0 ? (
          <p className="text-[#64748B] text-sm">No active tokens. Create one above to connect external agents.</p>
        ) : (
          <div className="space-y-3">
            {activeTokens.map((t) => (
              <div key={t.id} className="bg-[#111827] border border-[#334155]/30 rounded-lg p-4 flex items-center justify-between">
                <div className="space-y-1 text-sm">
                  <div className="font-mono text-[#00F5FF]">{t.id.slice(0, 12)}…</div>
                  <div className="text-[#94A3B8]">
                    Scope: <span className="text-white">{t.scope}</span> · Created {new Date(t.createdAt).toLocaleDateString()}
                    {t.expiresAt && ` · Expires ${new Date(t.expiresAt).toLocaleDateString()}`}
                  </div>
                  {t.lastUsedAt && <div className="text-xs text-[#64748B]">Last used: {new Date(t.lastUsedAt).toLocaleString()}</div>}
                </div>
                <button
                  onClick={() => handleRevoke(t.id)}
                  disabled={revoking === t.id}
                  className="px-3 py-1 text-sm border border-red-500/50 text-red-400 hover:bg-red-500/10 rounded"
                >
                  {revoking === t.id ? 'Revoking...' : 'Revoke'}
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {revokedTokens.length > 0 && (
        <div>
          <h2 className="font-semibold mb-3 text-[#64748B]">Revoked</h2>
          <div className="space-y-2 opacity-60 text-sm">
            {revokedTokens.map((t) => (
              <div key={t.id} className="font-mono">{t.id.slice(0, 12)}… — revoked {t.revokedAt ? new Date(t.revokedAt).toLocaleDateString() : ''}</div>
            ))}
          </div>
        </div>
      )}

      <div className="text-xs text-[#64748B] pt-4 border-t border-[#334155]/30">
        These tokens are validated by the core Unimatrix MCP server (packages/server). They are separate from your local API keys used by the web dashboard.
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { randomBytes } from "crypto";

export async function POST(request: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const userId = session.user.id;

  // Generate short-lived connect token (15 minutes)
  const token = randomBytes(32).toString("hex");
  const expires = new Date(Date.now() + 15 * 60 * 1000); // 15 min

  // Use VerificationToken table for simplicity (reusing existing pattern)
  // Store with identifier to scope to this user
  await prisma.verificationToken.create({
    data: {
      identifier: `mobile_connect:${userId}`,
      token,
      expires,
    },
  });

  return NextResponse.json({ connectToken: token }, { status: 201 });
}

/**
 * POST /api/auth/mfa/disable
 *
 * Disable MFA for the authenticated user after re-confirming their password.
 *
 * SOC2 CC6.1 / HIPAA §164.312(d)
 */

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { logAuthEvent } from "@/lib/audit";
import bcrypt from "bcryptjs";

export async function POST(req: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { password } = await req.json() as { password: string };
  if (!password) {
    return NextResponse.json({ error: "password is required" }, { status: 400 });
  }

  const user = await prisma.user.findUnique({
    where:  { id: session.user.id },
  // legacy shape: password lives in older schema; cast select to any to read it
  select: { password: true } as any,
  });

  const ip = req.headers.get("x-forwarded-for")?.split(",")[0].trim() ?? "unknown";

  if (!user?.password || !(await bcrypt.compare(password, (user as any).password))) {
    await logAuthEvent({
      userId:   session.user.id,
      action:   "mfa.disable_failed",
      ip,
      metadata: { reason: "invalid_password" },
    });
    return NextResponse.json({ error: "Incorrect password" }, { status: 403 });
  }

  await prisma.user.update({
    where: { id: session.user.id },
    data: {
      mfaEnabled:    false,
      mfaSecret:     null,
      mfaIv:         null,
      recoveryCodes: [],
    },
  });

  await logAuthEvent({
    userId:   session.user.id,
    action:   "mfa.disabled",
    ip,
    metadata: {},
  });

  return NextResponse.json({ success: true });
}

/**
 * POST /api/auth/mfa/recovery-codes
 *
 * Regenerate recovery codes (invalidates old ones).
 * Requires the user to confirm their TOTP token to prove they still have their authenticator.
 *
 * SOC2 CC6.1 / HIPAA §164.312(d)
 */

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { verifyTOTP, generateRecoveryCodes } from "@/lib/mfa";
import { prisma } from "@/lib/prisma";
import { logAuthEvent } from "@/lib/audit";

export async function POST(req: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { token } = await req.json() as { token: string };
  if (!token) {
    return NextResponse.json({ error: "token is required" }, { status: 400 });
  }

  const user = await prisma.user.findUnique({
    where:  { id: session.user.id },
  select: { mfaSecret: true, mfaIv: true, mfaEnabled: true } as any,
  });

  if (!user?.mfaEnabled || !(user as any).mfaSecret || !(user as any).mfaIv) {
    return NextResponse.json({ error: "MFA is not enabled" }, { status: 400 });
  }

  const ip = req.headers.get("x-forwarded-for")?.split(",")[0].trim() ?? "unknown";

  const valid = verifyTOTP(user.mfaSecret, token, user.mfaIv);
  if (!valid) {
    await logAuthEvent({
      userId:   session.user.id,
      action:   "mfa.recovery_codes_regenerate_failed",
      ip,
      metadata: { reason: "invalid_totp" },
    });
    return NextResponse.json({ error: "Invalid code" }, { status: 422 });
  }

  const plainCodes = await generateRecoveryCodes(session.user.id);

  await logAuthEvent({
    userId:   session.user.id,
    action:   "mfa.recovery_codes_regenerated",
    ip,
    metadata: {},
  });

  return NextResponse.json({ recoveryCodes: plainCodes });
}

import { NextRequest, NextResponse } from 'next/server';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { encryptApiKey } from '@/lib/crypto';
import { randomBytes } from "crypto";
import bcrypt from "bcryptjs";

const SUPPORTED_PROVIDERS = ['claude', 'openai', 'gemini', 'groq', 'ollama'];

// GET /api/llm-providers — list user's connected LLM providers (no keys)
export async function GET() {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const providers = await prisma.lLMProvider.findMany({
    where: { userId: session.user.id, isActive: true },
    select: {
      id: true,
      provider: true,
      model: true,
      label: true,
      keyPrefix: true,
      createdAt: true,
    },
    orderBy: { createdAt: 'asc' },
  });

  return NextResponse.json(providers);
}

// POST /api/llm-providers — connect a new LLM provider
export async function POST(request: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const { provider, model, apiKey, label } = await request.json();

  if (!provider || !SUPPORTED_PROVIDERS.includes(provider)) {
    return NextResponse.json(
      { error: `Provider must be one of: ${SUPPORTED_PROVIDERS.join(', ')}` },
      { status: 400 }
    );
  }
  if (!model?.trim()) {
    return NextResponse.json({ error: 'Model is required' }, { status: 400 });
  }
  if (provider !== 'ollama' && !apiKey?.trim()) {
    return NextResponse.json({ error: 'API key is required' }, { status: 400 });
  }

  const rawKey = provider === 'ollama' ? 'local' : apiKey.trim();
  const { encrypted, iv } = encryptApiKey(rawKey);
  const keyPrefix = rawKey.slice(0, 8) + '...';

  // Upsert — replace if same provider+model combo already exists
  const record = await prisma.lLMProvider.upsert({
    where: {
      userId_provider_model: {
        userId: session.user.id,
        provider,
        model: model.trim(),
      },
    },
    update: {
      keyEncrypted: encrypted,
      keyIv: iv,
      keyPrefix,
      label: label?.trim() || null,
      isActive: true,
    },
    create: {
      userId: session.user.id,
      provider,
      model: model.trim(),
      label: label?.trim() || null,
      keyEncrypted: encrypted,
      keyIv: iv,
      keyPrefix,
    },
  });

  // Auto-magic: provision per-LLM history organization space
  // This runs every time a user "logs into" / connects an LLM via the installer/onboarding/settings.
  // Unimatrix will now auto-store and organize future conversation history from this LLM
  // into its dedicated location.
  await ensureLLMHistoryLocation(session.user.id, provider, model.trim());

  // Background seed for history (supports non-MCP LLMs too via the general auto-log mechanism).
  // Since importRecentHistory requires a usable Unimatrix key and the llm package,
  // we do a simple direct seed of the "import note" memory into the history location.
  // Real history import/population happens on LLM use via autoLog / agent.
  try {
    const historyPalace = await prisma.palace.findFirst({
      where: { userId: session.user.id, name: 'LLM Histories', deletedAt: null },
    });
    if (historyPalace) {
      const locName = `${provider.charAt(0).toUpperCase() + provider.slice(1)} History`;
      const loc = await prisma.location.findFirst({
        where: { palaceId: historyPalace.id, name: locName },
      });
      if (loc) {
        // Seed a note about auto-capture (idempotent enough)
        await prisma.memory.create({
          data: {
            locationId: loc.id,
            content: `Background import note for ${provider}: History will be automatically captured and organized on future uses of this LLM (via the @unimatrix/llm auto-log, agent tasks, or when the LLM calls remember with sourceLlm). For providers supporting history APIs, extend importRecentHistory.`,
            tags: ['import-note', 'auto', provider, 'non-mcp-support'],
          },
        });
      }
    }
  } catch (e) {
    console.warn('Background history seed note skipped:', e);
  }

  return NextResponse.json(
    {
      id: record.id,
      provider: record.provider,
      model: record.model,
      label: record.label,
      keyPrefix: record.keyPrefix,
      createdAt: record.createdAt,
    },
    { status: 201 }
  );
}

// After saving the provider, auto-provision memory organization for its history
// This is the "installer" auto-magic: when you log into an LLM, Unimatrix auto-creates
// a dedicated space to store and organize all future (and past) conversation history from it.
async function ensureLLMHistoryLocation(userId: string, provider: string, model: string) {
  const historyPalaceName = 'LLM Histories';
  const locationName = `${provider.charAt(0).toUpperCase() + provider.slice(1)} History`;

  try {
    // Find or create the "LLM Histories" palace for this user
    let palace = await prisma.palace.findFirst({
      where: { userId, name: historyPalaceName, deletedAt: null },
    });

    if (!palace) {
      palace = await prisma.palace.create({
        data: {
          userId,
          name: historyPalaceName,
          description: 'Auto-organized conversation histories from all connected LLMs. Each LLM gets its own dedicated space for its full history.',
        },
      });
    }

    // Find or create the per-LLM location inside it
    let location = await prisma.location.findFirst({
      where: { palaceId: palace.id, name: locationName },
    });

    if (!location) {
      location = await prisma.location.create({
        data: {
          palaceId: palace.id,
          name: locationName,
          description: `Full auto-stored history of all interactions with ${provider} (${model}). Unimatrix automatically files new conversations here based on the LLM source when you use it via agents or integrations.`,
          position: 0,
        },
      });
    }

    // Seed or update a note about auto-storage (idempotent-ish via description)
    // (We could query for a memory with specific tag, but for simplicity we just ensure the space exists)

    console.log(`[Auto-magic] Ensured history location for ${provider}: ${location.id} in palace ${palace.id}`);
  } catch (err) {
    console.warn(`[Auto-magic] Failed to provision history location for ${provider}:`, err);
  }
}

/**
 * Unimatrix MCP HTTP Endpoint (serverless-friendly)
 * POST /api/mcp  — handles all MCP tool calls over HTTP+JSON
 * GET  /api/mcp  — returns server info (for discovery)
 *
 * This route handler version runs on Vercel (or any Next.js deployment).
 * For the full persistent dedicated MCP server, see packages/server (Fastify)
 * and the custom server.ts + worker setup (recommended for Collab Room + always-on).
 *
 * Authentication: Bearer <umx_...> API key in Authorization header
 * Used by Claude Desktop, Claude Code, Cursor, and any MCP client
 * that supports the streamable-http transport.
 */

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { textToBytes, bytesToText } from '@/lib/prisma-utils';
import bcrypt from "bcryptjs";

// Extend NextRequest for internal org context passing (from API key auth to MCP handlers)
declare module "next/server" {
  interface NextRequest {
    _unimatrixOrgId?: string | null;
  }
}

// ─── API key auth ─────────────────────────────────────────────────────────────

async function resolveUser(req: NextRequest): Promise<string | null> {
  const auth = req.headers.get("authorization") ?? "";
  if (!auth.startsWith("Bearer umx_")) return null;
  const raw = auth.slice(7); // strip "Bearer "

  // Prefix is first 12 chars ("umx_" + 8 hex chars)
  const prefix = raw.slice(0, 12);
  const keys = await prisma.apiKey.findMany({
    where: { keyPrefix: prefix, revokedAt: null },
    select: { id: true, userId: true, keyHash: true, organizationId: true },
  });

  for (const k of keys) {
    const match = await bcrypt.compare(raw, k.keyHash);
    if (match) {
      // Update last-used timestamp async (don't await)
      prisma.apiKey.update({ where: { id: k.id }, data: { lastUsed: new Date() } }).catch(() => {});
      // Attach org to request for downstream (tools/call path)
      req._unimatrixOrgId = k.organizationId;
      return k.userId;
    }
  }
  return null;
}

// ─── MCP protocol helpers ─────────────────────────────────────────────────────

type McpRequest = {
  jsonrpc: "2.0";
  id: string | number;
  method: string;
  params?: Record<string, unknown>;
};

function ok(id: string | number, result: unknown) {
  return NextResponse.json({ jsonrpc: "2.0", id, result }, { status: 200 });
}

function err(id: string | number | null, code: number, message: string) {
  return NextResponse.json({ jsonrpc: "2.0", id, error: { code, message } }, { status: 200 });
}

function textContent(text: string) {
  return { content: [{ type: "text", text }] };
}

