// ─── Tool handlers ────────────────────────────────────────────────────────────

export async function handleTool(
  name: string,
  args: Record<string, unknown>,
  userId: string
): Promise<string> {
  switch (name) {
    // ── list_palaces ────────────────────────────────────────────────────────
    case "unimatrix_list_palaces": {
      const palaces = await prisma.palace.findMany({
        where: { userId, deletedAt: null },
        orderBy: { createdAt: "desc" },
        select: { id: true, name: true, description: true, isPublic: true, createdAt: true, updatedAt: true },
      });
      if (!palaces.length) return "You have no memory palaces yet. Create one with unimatrix_create_palace.";
      return palaces.map((p: any) =>
        `## ${p.name}\n- ID: \`${p.id}\`\n${p.description ? `- ${p.description}\n` : ""}- ${p.isPublic ? "Public" : "Private"} · Created ${new Date(p.createdAt).toLocaleDateString()}`
      ).join("\n\n");
    }

    // ── get_palace ──────────────────────────────────────────────────────────
    case "unimatrix_get_palace": {
      const palaceId = args.palace_id as string;
      const palace = await prisma.palace.findFirst({
        where: { id: palaceId, userId, deletedAt: null },
        include: {
          locations: {
            where: { deletedAt: null, parentId: null },
            orderBy: { position: "asc" },
            include: {
              memories: { where: { deletedAt: null }, orderBy: { createdAt: "desc" }, take: 50 },
              children: {
                where: { deletedAt: null },
                orderBy: { position: "asc" },
                include: { memories: { where: { deletedAt: null }, orderBy: { createdAt: "desc" }, take: 50 } },
              },
            },
          },
        },
      });
      if (!palace) return "Palace not found or access denied.";

      const renderMems = (memories: { id: string; content: string; tags: string[] }[], indent = "") =>
        memories.map(m => `${indent}- \`${m.id}\`: ${m.content.slice(0, 200)}${m.content.length > 200 ? "…" : ""}${m.tags.length ? ` [${m.tags.join(", ")}]` : ""}`).join("\n");

      const lines = [`# ${palace.name}`, palace.description ? `> ${palace.description}` : "", `**ID**: \`${palace.id}\`\n`];
      for (const loc of palace.locations) {
        lines.push(`### ${loc.name} (\`${loc.id}\`)`);
        if (loc.memories.length) lines.push(renderMems(loc.memories, "  "));
        for (const child of loc.children) {
          lines.push(`  #### ${child.name} (\`${child.id}\`)`);
          if (child.memories.length) lines.push(renderMems(child.memories, "    "));
        }
      }
      return lines.join("\n");
    }

    // ── search_memories ─────────────────────────────────────────────────────
    case "unimatrix_search_memories": {
      const query = args.query as string;
      const limit = Math.min(Number(args.limit ?? 20), 50);
      const palaceFilter = args.palace_id ? { palace: { id: args.palace_id as string } } : {};

      const memories = await prisma.memory.findMany({
        where: {
          deletedAt: null,
          location: { ...palaceFilter, palace: { userId } },
          OR: [
            { content: { contains: query, mode: "insensitive" } },
            { tags: { has: query } },
          ],
        },
        take: limit,
        orderBy: { createdAt: "desc" },
        include: { location: { include: { palace: { select: { id: true, name: true } } } } },
      });

      if (!memories.length) return `No memories found for "${query}".`;
      return memories.map((m: any) =>
        `## ${m.location.palace.name} › ${m.location.name}\n**ID**: \`${m.id}\`\n${m.content}\n${m.tags.length ? `Tags: ${m.tags.join(", ")}` : ""}`
      ).join("\n\n---\n\n");
    }

    // ── store_memory ─────────────────────────────────────────────────────────
    case "unimatrix_store_memory": {
      let locationId = args.location_id as string | undefined;
      const content = args.content as string;
      let tags = (args.tags as string[]) ?? [];

      // Support sourceLlm at args root (injected by /api/tools/call for non-MCP LLMs, or passed in MCP args)
      const sourceLlm = (args.sourceLlm as string) || (args.source_llm as string) || (args["sourceLlm"] as string);
      if (sourceLlm && typeof sourceLlm === "string") {
        const llmTag = `llm-source:${sourceLlm}`;
        if (!tags.includes(llmTag)) tags = [...tags, llmTag];
      }

      // Auto-resolve to per-LLM history location if location_id omitted but sourceLlm present.
      // This makes non-MCP LLMs (after connecting in onboarding) "just work" for auto-organized history
      // without needing to discover + specify the exact location ID every time.
      if (!locationId && sourceLlm && typeof sourceLlm === "string") {
        try {
          const cap = sourceLlm.charAt(0).toUpperCase() + sourceLlm.slice(1);
          const locName = `${cap} History`;
          const historiesPalace = await prisma.palace.findFirst({
            where: { userId, name: "LLM Histories", deletedAt: null },
          });
          if (historiesPalace) {
            const histLoc = await prisma.location.findFirst({
              where: { palaceId: historiesPalace.id, name: locName, deletedAt: null },
            });
            if (histLoc) {
              locationId = histLoc.id;
            }
          }
          // Also check inside "Mobile" palace (created by mobile installer auto-magic) for device context
          if (!locationId) {
            const mobilePalace = await prisma.palace.findFirst({
              where: { userId, name: "Mobile", deletedAt: null },
            });
            if (mobilePalace) {
              const mobileHist = await prisma.location.findFirst({
                where: { palaceId: mobilePalace.id, name: locName, deletedAt: null },
              });
              if (mobileHist) locationId = mobileHist.id;
            }
          }
        } catch (e) {
          console.warn("[store_memory] auto-resolve history loc failed:", e);
        }
      }

      if (!locationId) {
        return "location_id is required (or pass sourceLlm at call root for auto-resolve to your per-LLM History location). Get IDs via unimatrix_list_palaces + unimatrix_get_palace.";
      }

      // Verify location belongs to user
      const location = await prisma.location.findFirst({
        where: { id: locationId, palace: { userId }, deletedAt: null },
        select: { id: true },
      });
      if (!location) return "Location not found or access denied.";

      const memory = await prisma.memory.create({
        data: {
          locationId,
          content: textToBytes(content) as any,
          // Prisma expects nested create for tags; map to the shape.
          tags: { create: tags.map(t => ({ tag: String(t) })) },
        },
      });
      return `Memory stored. ID: \`${memory.id}\`\n\nContent: ${bytesToText(memory.content)}${sourceLlm ? ` (auto-filed for ${sourceLlm})` : ""}`;
    }

    // ── list_memories ─────────────────────────────────────────────────────────
    case "unimatrix_list_memories": {
      const locationId = args.location_id as string;
      const limit = Math.min(Number(args.limit ?? 50), 100);
      const offset = Number(args.offset ?? 0);

      const location = await prisma.location.findFirst({
        where: { id: locationId, palace: { userId }, deletedAt: null },
        select: { id: true, name: true },
      });
      if (!location) return "Location not found or access denied.";

      const [memories, total] = await Promise.all([
        prisma.memory.findMany({
          where: { locationId, deletedAt: null },
          orderBy: { createdAt: "desc" },
          take: limit,
          skip: offset,
        }),
        prisma.memory.count({ where: { locationId, deletedAt: null } }),
      ]);

      if (!memories.length) return "No memories at this location.";
      const lines = [`# ${location.name} — ${total} memories (showing ${memories.length})\n`];
      for (const m of memories) {
        lines.push(`**\`${m.id}\`**: ${m.content}`);
        if (m.tags.length) lines.push(`Tags: ${m.tags.join(", ")}`);
        lines.push(`_${new Date(m.createdAt).toLocaleDateString()}_\n`);
      }
      return lines.join("\n");
    }

    // ── create_palace ─────────────────────────────────────────────────────────
    case "unimatrix_create_palace": {
      const user = await prisma.user.findUnique({ where: { id: userId }, select: { tier: true } });
      if (user?.tier === "free") {
        const count = await prisma.palace.count({ where: { userId, deletedAt: null } });
        if (count >= 3) return "Free tier is limited to 3 palaces. Upgrade to Pro at deployunimatrix.com/pricing.";
      }
      const palace = await prisma.palace.create({
        data: { userId, name: args.name as string, description: (args.description as string) ?? null, isPublic: (args.is_public as boolean) ?? false },
      });
      return `Palace created: **${palace.name}** (\`${palace.id}\`)\nUse unimatrix_create_location to add rooms.`;
    }

    // ── create_location ───────────────────────────────────────────────────────
    case "unimatrix_create_location": {
      const palace = await prisma.palace.findFirst({
        where: { id: args.palace_id as string, userId, deletedAt: null },
        select: { id: true },
      });
      if (!palace) return "Palace not found or access denied.";

      const location = await prisma.location.create({
        data: {
          palaceId: palace.id,
          name: args.name as string,
          description: (args.description as string) ?? null,
          parentId: (args.parent_id as string) ?? null,
          position: Number(args.position ?? 0),
        },
      });
      return `Location created: **${location.name}** (\`${location.id}\`)\nStore memories with location_id: "${location.id}"`;
    }

    // ── update_memory ─────────────────────────────────────────────────────────
    case "unimatrix_update_memory": {
      const memoryId = args.memory_id as string;
      const memory = await prisma.memory.findFirst({
        where: { id: memoryId, location: { palace: { userId } }, deletedAt: null },
        select: { id: true },
      });
      if (!memory) return "Memory not found or access denied.";

      const updatedData: any = {};
      if (args.content) updatedData.content = textToBytes(args.content as string);
      if (args.tags) {
        // replace tags naively — for now delete/create pattern would be better
        updatedData.tags = { deleteMany: {}, create: (args.tags as string[]).map(t => ({ tag: String(t) })) };
      }
      const updated = await prisma.memory.update({ where: { id: memoryId }, data: updatedData });
      return `Memory updated. ID: \`${updated.id}\`\n${bytesToText(updated.content)}`;
    }

    // ── get_recent ────────────────────────────────────────────────────────────
    case "unimatrix_get_recent": {
      const limit = Math.min(Number(args.limit ?? 10), 50);
      const memories = await prisma.memory.findMany({
        where: { deletedAt: null, location: { palace: { userId } } },
        orderBy: { lastAccessed: "desc" },
        take: limit,
        include: { location: { include: { palace: { select: { id: true, name: true } } } } },
      });
      if (!memories.length) return "No memories found.";
      return memories.map((m: any) =>
        `**${m.location.palace.name} › ${m.location.name}** (\`${m.id}\`)\n${String(m.content).slice(0, 300)}${String(m.content).length > 300 ? "…" : ""}\n_${new Date(m.lastAccessed).toLocaleDateString()}_`
      ).join("\n\n---\n\n");
    }

    default:
      return `Unknown tool: ${name}`;
  }
}

// ─── Route handlers ───────────────────────────────────────────────────────────

export async function GET() {
  return NextResponse.json({
    name: "unimatrix-mcp-server",
    version: "1.0.0",
    description: "Unimatrix memory palace MCP endpoint",
    protocolVersion: "2024-11-05",
    capabilities: { tools: {} },
  });
}

export async function POST(req: NextRequest) {
  // Auth
  const userId = await resolveUser(req);
  if (!userId) {
    return NextResponse.json(
      { jsonrpc: "2.0", id: null, error: { code: -32001, message: "Unauthorized — invalid or missing API key." } },
      { status: 401 }
    );
  }

  let body: McpRequest;
  try {
    body = await req.json();
  } catch {
    return err(null as unknown as number, -32700, "Parse error");
  }

  const { id, method, params } = body;

  // ── initialize ──────────────────────────────────────────────────────────────
  if (method === "initialize") {
    return ok(id, {
      protocolVersion: "2024-11-05",
      capabilities: { tools: {} },
      serverInfo: { name: "unimatrix-mcp-server", version: "1.0.0" },
    });
  }

  // ── tools/list ──────────────────────────────────────────────────────────────
  if (method === "tools/list") {
    // Use central registry so collab tools appear automatically
    const { getAllTools } = await import("@/lib/tools/registry");
    const tools = getAllTools();
    return ok(id, { tools });
  }

  // ── tools/call ──────────────────────────────────────────────────────────────
  if (method === "tools/call") {
    const toolName = params?.name as string;
    const args = (params?.arguments ?? {}) as Record<string, unknown>;

    if (!toolName) return err(id, -32602, "Missing tool name");

    // Extract agent context (used for telemetry + HITL)
    const agentName = (args.agent_name || args.sender_name || 'unknown-agent') as string;
    const organizationId = req._unimatrixOrgId || null;

    try {
      // === NEW: Spend Limit Check + Pre-execution Cost Estimation ===
      const { 
        checkSpendLimit, 
        requiresHumanApproval, 
        createPendingAction,
        estimateCostBeforeExecution 
      } = await import('@/lib/telemetry/agent-usage');

      // Rough pre-estimation (agents should pass better estimates in future)
      const estimatedCost = estimateCostBeforeExecution(
        (args.provider as string) || 'openai',
        (args.model as string) || 'gpt-4o',
        1200, // assumed prompt tokens
        600
      );

      const projectedSpend = (await checkSpendLimit(agentName, organizationId || undefined)).currentSpend + estimatedCost;

      const spendCheck = await checkSpendLimit(agentName, organizationId || undefined);
      if (projectedSpend > spendCheck.limit) {
        return ok(id, {
          status: 'blocked',
          reason: 'would_exceed_daily_spend_limit',
          estimated_cost: estimatedCost,
          current_spend: spendCheck.currentSpend,
          limit: spendCheck.limit,
          message: 'This call would exceed the daily spend limit.',
        });
      }

      if (!spendCheck.allowed) {
        return ok(id, {
          status: 'blocked',
          reason: 'daily_spend_limit_exceeded',
          current_spend: spendCheck.currentSpend,
          limit: spendCheck.limit,
        });
      }

      // === NEW: HITL (Human-in-the-Loop) Check ===
      const hitlRequired =
        (args.hitl_required as boolean) ||
        (await requiresHumanApproval(agentName, toolName, organizationId || undefined));

      if (hitlRequired) {
        const pending = await createPendingAction({
          roomId: (args.room_id as string) || 'global',
          agentName,
          toolName,
          args,
          requestedBy: agentName,
          expiresInMinutes: 60,
        });

        // Fire notification (non-blocking)
        import('@/lib/notifications/pending-action')
          .then(({ notifyPendingActionCreated }) =>
            notifyPendingActionCreated({
              id: pending.id,
              roomId: pending.roomId,
              agentName,
              toolName,
              requestedBy: agentName,
            })
          )
          .catch(() => {});

        return ok(id, {
          status: 'pending_approval',
          pending_action_id: pending.id,
          message: 'This action requires human approval before execution.',
          tool_name: toolName,
        });
      }

      // Normal execution path
      const { executeTool } = await import('@/lib/tools/registry');
      const result = await executeTool(toolName, args, { userId, organizationId });

      // Best-effort telemetry logging (non-blocking)
      const { logToolExecutionTelemetry } = await import('@/lib/telemetry/agent-usage');
      logToolExecutionTelemetry(toolName, agentName, result, args).catch(() => {});

      return ok(id, result);
    } catch (e) {
      const msg = e instanceof Error ? e.message : String(e);
      console.error(`[MCP] Tool error (${toolName}):`, msg);
      return ok(id, textContent(`Error: ${msg}`));
    }
  }

  // ── notifications/initialized (client ack — no response needed) ─────────────
  if (method === "notifications/initialized") {
    return new NextResponse(null, { status: 204 });
  }

  return err(id, -32601, `Method not found: ${method}`);
}

import { NextRequest, NextResponse } from 'next/server';
import { auth } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

interface CreateMemoryPayload {
  ciphertext: string;
  nonce: string;
  signature: string;
  context?: string;
  importance: 'low' | 'medium' | 'high';
}

export async function POST(req: NextRequest) {
  try {
    // Authenticate user
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Parse encrypted memory payload
    const body = (await req.json()) as CreateMemoryPayload;

    const { ciphertext, nonce, signature, context, importance } = body;

    // Validate required fields
    if (!ciphertext || !nonce || !signature) {
      return NextResponse.json(
        { error: 'Missing encryption fields: ciphertext, nonce, signature' },
        { status: 400 }
      );
    }

    // TODO: In Phase 1F, verify signature against user's public key
    // For now, just store the encrypted payload
    console.log('[Memory] Creating encrypted memory for user:', session.user.id);
    console.log('[Memory] Context:', context || 'default');
    console.log('[Memory] Importance:', importance);
    console.log('[Memory] Ciphertext length:', ciphertext.length);

    // Store encrypted memory in database
    // Note: The server stores ciphertext only. It cannot decrypt without the user's password.
    // TODO: Wire this into actual Prisma memory model once schema is finalized
    // For now, return success response

    return NextResponse.json(
      {
        success: true,
        message: 'Memory encrypted and stored securely',
        memoryId: `mem_${Date.now()}`,
        details: {
          encrypted: true,
          ciphertextLength: ciphertext.length,
          context: context || 'default',
          importance,
          timestamp: new Date().toISOString(),
        },
      },
      { status: 201 }
    );
  } catch (error) {
    console.error('[Memory] Error creating memory:', error);
    return NextResponse.json(
      { error: 'Failed to create encrypted memory' },
      { status: 500 }
    );
  }
}

/**
 * POST /api/memory/store
 *
 * REST store endpoint for non-MCP LLMs (ChatGPT, Gemini, Perplexity, etc.).
 *
 * Request body:
 *   { content: string, space_id?: string, tags?: string[], source_llm?: string, ttl_days?: number }
 *
 * Response:
 *   { success: true, memoryId: string }
 *
 * The CSMTER Librarian pipeline (embed → quantize → classify → triples) runs
 * fire-and-forget after the HTTP response is sent.
 */

import { NextRequest, NextResponse } from 'next/server';
import { getUserIdFromRequest }       from '@/lib/api-auth';
import { prisma }                     from '@unimatrix/db';

const MCP_SERVER_URL = process.env.MCP_SERVER_URL ?? 'https://unimatrix-mcp.fly.dev';

export async function POST(request: NextRequest): Promise<NextResponse> {
  const userId = await getUserIdFromRequest(request);
  if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const body = await request.json().catch(() => null);
  if (!body?.content) return NextResponse.json({ error: '"content" is required' }, { status: 400 });

  const {
    content,
    space_id,
    tags       = [],
    source_llm,
    ttl_days,
  } = body as {
    content:    string;
    space_id?:  string;
    tags?:      string[];
    source_llm?: string;
    ttl_days?:  number;
  };

  try {
    // Add source tag for non-MCP LLMs
    const finalTags = source_llm
      ? [...new Set([...tags, `llm-source:${source_llm}`])]
      : tags;

    // TTL: convert ttl_days to an expiry timestamp
    const expiresAt = ttl_days && ttl_days > 0
      ? new Date(Date.now() + ttl_days * 86_400_000)
      : null;

    // Insert episodic row (content is stored as encrypted bytes in production;
    // here we store as buffer via Prisma — encryption is handled by the middleware layer)
    const memory = await prisma.memory.create({
      data: {
        userId,
        spaceId:    space_id ?? null,
        content:    new Uint8Array(Buffer.from(content, 'utf8')),
        contentIv:  new Uint8Array(16), // placeholder IV — encryption layer overwrites this
        source:     'api',
        status:     'active',
      },
    });

    // Apply TTL if requested (expiresAt added in migration 006 — set via raw SQL
    // until Prisma client is regenerated to include the new column)
    if (expiresAt) {
      await prisma.$executeRaw`
        UPDATE memories SET expires_at = ${expiresAt} WHERE id = ${memory.id}::uuid
      `;
    }

    // Insert tags
    if (finalTags.length > 0) {
      await prisma.memoryTag.createMany({ // eslint-disable-line @typescript-eslint/no-explicit-any
        data: finalTags.map(tag => ({ memoryId: memory.id, tag })),
        skipDuplicates: true,
      });
    }

    // Fire-and-forget CSMTER Librarian pipeline (embed → quantize → classify → triples),
    // delegated to the MCP server which owns the librarian implementation.
    setImmediate(() => {
      fetch(`${MCP_SERVER_URL}/api/librarian/process`, {
        method: 'POST',
        headers: {
          'Content-Type':  'application/json',
          'Authorization': `Bearer ${process.env.INTERNAL_API_SECRET ?? 'dev-internal-secret'}`,
        },
        body: JSON.stringify({
          memoryId:  memory.id,
          userId,
          content,
          spaceId:   space_id,
          sourceLlm: source_llm,
        }),
      }).catch(err => {
        console.error(`[/api/memory/store] Librarian job failed for ${memory.id}:`, err);
      });
    });

    return NextResponse.json({ success: true, memoryId: memory.id }, { status: 201 });
  } catch (err) {
    console.error('[/api/memory/store]', err);
    return NextResponse.json({ error: 'Store failed' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

// GET /api/palaces/[id]/share — list who this palace is shared with
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id: palaceId } = await params;

  // Verify caller owns the palace
  const palace = await prisma.palace.findFirst({
    where: { id: palaceId, userId: session.user.id, deletedAt: null },
  });

  if (!palace) {
    return NextResponse.json({ error: "Palace not found" }, { status: 404 });
  }

  const shares = await prisma.palaceShare.findMany({
    where: { palaceId },
    include: {
      sharedWith: { select: { id: true, name: true, email: true, image: true } },
    },
    orderBy: { createdAt: "asc" },
  });

  return NextResponse.json(
    shares.map((s: any) => ({
      shareId: s.id,
      user: s.sharedWith,
      permission: s.permission,
      sharedAt: s.createdAt,
    }))
  );
}

// POST /api/palaces/[id]/share — share a palace with a friend
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id: palaceId } = await params;
  const { userId, permission = "view" } = await request.json();

  if (!userId) {
    return NextResponse.json({ error: "userId is required" }, { status: 400 });
  }

  if (!["view", "edit"].includes(permission)) {
    return NextResponse.json({ error: "permission must be 'view' or 'edit'" }, { status: 400 });
  }

  if (userId === session.user.id) {
    return NextResponse.json({ error: "You cannot share with yourself" }, { status: 400 });
  }

  // Verify caller owns the palace
  const palace = await prisma.palace.findFirst({
    where: { id: palaceId, userId: session.user.id, deletedAt: null },
  });

  if (!palace) {
    return NextResponse.json({ error: "Palace not found" }, { status: 404 });
  }

  // Verify they are friends (either direction, accepted)
  const friendship = await prisma.friendship.findFirst({
    where: {
      status: "accepted",
      OR: [
        { requesterId: session.user.id, addresseeId: userId },
        { requesterId: userId, addresseeId: session.user.id },
      ],
    },
  });

  if (!friendship) {
    return NextResponse.json({ error: "You can only share with friends" }, { status: 403 });
  }

  // Upsert: if already shared, update permission
  const share = await prisma.palaceShare.upsert({
    where: { palaceId_sharedWithId: { palaceId, sharedWithId: userId } },
    create: {
      palaceId,
      sharedById: session.user.id,
      sharedWithId: userId,
      permission,
    },
    update: { permission },
    include: {
      sharedWith: { select: { id: true, name: true, email: true, image: true } },
    },
  });

  return NextResponse.json(
    {
      shareId: share.id,
      user: share.sharedWith,
      permission: share.permission,
      sharedAt: share.createdAt,
    },
    { status: 201 }
  );
}

/**
 * POST /api/tools/call
 *
 * Universal tool execution endpoint for non-MCP LLMs and agents.
 *
 * Accepts a simple JSON payload and translates it into an internal
 * MCP `tools/call` invocation.
 *
 * Request body:
 *   {
 *     "toolName": "unimatrix_search_memories",
 *     "args": {
 *       "query": "authentication decisions",
 *       "limit": 5
 *     }
 *   }
 *
 * Success response (200):
 *   {
 *     "status": "success",
 *     "result": "string content returned by the tool",
 *     "toolName": "unimatrix_search_memories"
 *   }
 *
 * Error responses:
 *   400 — Malformed request (missing toolName, bad args shape, etc.)
 *   401 — Missing or invalid API key
 *   404 — Unknown tool name
 *   500 — Internal MCP / database error
 *
 * Authentication: Required — Bearer umx_... API key (same as /api/mcp)
 */

import { NextRequest, NextResponse } from "next/server";
import { getAuthContext } from "@/lib/api-auth";
import { rateLimiters } from "@/lib/rate-limit";
import {
  callMcpTool,
  type ToolCallRequest,
  type ToolCallSuccessResponse,
} from "@/lib/mcp-client";

export const dynamic = "force-dynamic";

interface ErrorResponseBody {
  status: "error";
  error: string;
  code: string;
  toolName?: string;
}

export async function POST(
  req: NextRequest
): Promise<NextResponse<ToolCallSuccessResponse | ErrorResponseBody>> {
  let userId: string | null = null;
  let organizationId: string | null = null;

  try {
    // ─── 1. Authentication + Organization (required for tool execution) ─────
    const auth = await getAuthContext(req);

    if (!auth?.userId) {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: "Unauthorized — missing or invalid API key. Use Authorization: Bearer umx_...",
          code: "UNAUTHORIZED",
        },
        { status: 401 }
      );
    }

    // For org-scoped tools (collab.*), require a valid organization
    if (!auth.organizationId) {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: "Forbidden — this tool requires an organization-scoped API key or active organization membership.",
          code: "FORBIDDEN",
        },
        { status: 403 }
      );
    }

    userId = auth.userId;
    organizationId = auth.organizationId;

    // ─── 1b. Rate limit per API key (best effort identifier) ───────────────
    // Extract prefix for rate limiting key (avoids full key material)
    const authHeader = req.headers.get("authorization") ?? "";
    const rateKey = authHeader.startsWith("Bearer umx_") ? authHeader.slice(7, 19) : `user:${userId}`;
    const rl = await rateLimiters.apiKeyToolExecution(rateKey);
    if (!rl.success) {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: "Rate limit exceeded for tool execution. Retry later.",
          code: "RATE_LIMITED",
        },
        { status: 429, headers: { "Retry-After": Math.ceil((rl.reset - Date.now()) / 1000).toString() } }
      );
    }

    // ─── 2. Parse and validate request body ─────────────────────────────────
    let body: unknown;
    try {
      body = await req.json();
    } catch {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: "Invalid JSON body. Expected application/json.",
          code: "VALIDATION_ERROR",
        },
        { status: 400 }
      );
    }

    if (!body || typeof body !== "object") {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: "Request body must be a JSON object.",
          code: "VALIDATION_ERROR",
        },
        { status: 400 }
      );
    }

    const { toolName, args, sourceLlm } = body as Partial<ToolCallRequest> & { sourceLlm?: string };

    if (!toolName || typeof toolName !== "string") {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: "Missing or invalid 'toolName' (must be a non-empty string).",
          code: "VALIDATION_ERROR",
        },
        { status: 400 }
      );
    }

    // args is optional in the payload; default to empty object
    let safeArgs: Record<string, unknown> =
      args && typeof args === "object" && !Array.isArray(args) ? { ...args } : {};

    // Support top-level sourceLlm for non-MCP LLMs (e.g. Gemini, ChatGPT via REST tools)
    // This allows automatic tagging/organization of memories by the specific LLM source,
    // even for LLMs that don't speak MCP.
    if (sourceLlm && typeof sourceLlm === 'string') {
      safeArgs.sourceLlm = sourceLlm;
    }

    // ─── 3. Execute via internal MCP client (translates to tools/call) ──────
    // The MCP layer now handles HITL + telemetry internally
    const mcpResult = await callMcpTool(toolName, safeArgs, userId, organizationId);

    // Extract the primary text content (consistent with MCP text responses)
    const primaryText =
      mcpResult?.content?.[0]?.text ??
      (typeof mcpResult === "string" ? mcpResult : JSON.stringify(mcpResult));

    const successResponse: ToolCallSuccessResponse = {
      status: "success",
      result: primaryText,
      toolName,
    };

    return NextResponse.json(successResponse, { status: 200 });
  } catch (error) {
    const toolNameForError =
      ((req as unknown) as { _parsedBody?: { toolName?: string } })._parsedBody?.toolName ?? "unknown";

    console.error(`[/api/tools/call] Tool execution failed (${toolNameForError}):`, error);

    const message = error instanceof Error ? error.message : "Unknown internal error";

    // Detect common classes of errors
    if (message.toLowerCase().includes("unknown tool")) {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: message,
          code: "NOT_FOUND",
          toolName: toolNameForError,
        },
        { status: 404 }
      );
    }

    if (message.toLowerCase().includes("unauthorized") || message.toLowerCase().includes("access denied")) {
      return NextResponse.json<ErrorResponseBody>(
        {
          status: "error",
          error: message,
          code: "UNAUTHORIZED",
          toolName: toolNameForError,
        },
        { status: 401 }
      );
    }

    // Generic server error (never leak stack traces to clients)
    return NextResponse.json<ErrorResponseBody>(
      {
        status: "error",
        error: "Tool execution failed. Please check the tool name and arguments.",
        code: "INTERNAL_ERROR",
        toolName: toolNameForError,
      },
      { status: 500 }
    );
  }
}

