export class CollabError extends Error {
  constructor(
    message: string,
    public code: 'NOT_FOUND' | 'FORBIDDEN' | 'VALIDATION_ERROR' | 'INTERNAL',
    public status: number = 400
  ) {
    super(message);
    this.name = 'CollabError';
  }
}

