/**
 * Create a new collaboration room within the organization.
 */
export async function createRoom(
  input: CreateRoomInput,
  organizationId: string
): Promise<CreateRoomResult> {
  const validated = CreateRoomInput.parse(input);

  if (!organizationId) {
    throw new CollabError('Organization context required', 'FORBIDDEN', 403);
  }

  const room = await prisma.collabRoom.create({
    data: {
      organizationId,
      name: validated.name,
      description: validated.description ?? null,
      isPrivate: validated.isPrivate,
    },
  });

  logCollabAudit({
    organizationId,
    action: 'collab.room.created',
    targetId: room.id,
    metadata: { name: validated.name },
  }).catch(() => {});

  return {
    room_id: room.id,
    name: room.name,
  };
}

/**
 * List rooms for the given organization (lightweight, no message counts for perf).
 */
export async function listRooms(
  input: ListRoomsInput = {},
  organizationId: string
): Promise<CollabRoomDTO[]> {
  const validated = ListRoomsInput.parse(input);

  if (!organizationId) {
    throw new CollabError('Organization context required', 'FORBIDDEN', 403);
  }

  const rooms = await prisma.collabRoom.findMany({
    where: { organizationId },
    orderBy: { createdAt: 'desc' },
    take: validated.limit,
    select: {
      id: true,
      name: true,
      description: true,
      isPrivate: true,
      createdAt: true,
    },
  });

  return rooms.map((r: any) => ({
    id: r.id,
    name: r.name,
    description: r.description,
    is_private: r.isPrivate,
    created_at: r.createdAt.toISOString(),
  }));
}

// ============================================================================
// WEBHOOK DISPATCH (Production: Enqueue via Upstash QStash / Inngest / Bull)
// ============================================================================

async function dispatchMessageWebhooks(
  roomId: string,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  message: any,
  organizationId: string
) {
  const subscriptions = await prisma.webhookSubscription.findMany({
    where: {
      roomId,
      isActive: true,
    },
  });

  if (subscriptions.length === 0) return;

  const payload = {
    event: 'message.created',
    room_id: roomId,
    message: {
      id: message.id,
      sender_name: message.senderName,
      sender_type: message.senderType,
      message: message.message,
      metadata: message.metadata,
      created_at: message.createdAt.toISOString(),
    },
    organization_id: organizationId,
  };

  // Production recommendation: instead of in-process fan-out,
  // await qstashClient.publishJSON({ url: '/api/internal/deliver-webhooks', body: { roomId, messageId: message.id } })
  // This gives you retries, DLQ, visibility, and avoids tying up the MCP/REST handler.

  await Promise.allSettled(
    subscriptions.map(async (sub: any) => {
      // Per-target delivery protection
      const deliveryRl = await rateLimiters.webhookDelivery(sub.targetUrl);
      if (!deliveryRl.success) {
        console.warn(`[webhook] Skipping delivery to ${sub.targetUrl} (rate limited)`);
        return;
      }

      try {
        const signature = signWebhookPayload(sub.webhookSecret, payload);

        const res = await fetch(sub.targetUrl, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'X-Unimatrix-Signature': signature,
            'X-Unimatrix-Event': 'message.created',
            'User-Agent': 'Unimatrix-Webhooks/1.0',
          },
          body: JSON.stringify(payload),
          signal: AbortSignal.timeout(8000),
        });

        if (!res.ok) {
          throw new Error(`HTTP ${res.status}`);
        }

        // Update last triggered (fire and forget)
        prisma.webhookSubscription
          .update({
            where: { id: sub.id },
            data: { lastTriggeredAt: new Date() },
          })
          .catch(() => {});
      } catch (err) {
        console.error(`[webhook] Failed to deliver to ${sub.targetUrl}:`, err);
        // In production: write to a WebhookDeliveryAttempts table or send to QStash DLQ topic.
        // Consider marking subscription inactive after N consecutive failures.
      }
    })
  );
}

/**
 * lib/db.ts
 *
 * Raw PostgreSQL pool for CSMTER routes that need direct SQL access
 * (pgvector HNSW, BM25 tsvector queries) that Prisma ORM can't express.
 *
 * Lazily initialises the pool on first use so that Next.js build-time
 * static analysis / page-data collection does NOT throw when DATABASE_URL
 * is absent from the Docker build environment.  The error surfaces at
 * request time, not at module-import time.
 */

import { Pool } from 'pg';

declare global {
  // eslint-disable-next-line no-var
  var __pgPool: Pool | undefined;
}

function getPool(): Pool {
  if (globalThis.__pgPool) return globalThis.__pgPool;

  const connectionString = process.env.DATABASE_URL;
  if (!connectionString) {
    throw new Error('DATABASE_URL environment variable is not set');
  }

  globalThis.__pgPool = new Pool({
    connectionString,
    max: 10,
    idleTimeoutMillis: 30_000,
    connectionTimeoutMillis: 5_000,
    ssl: connectionString.includes('neon.tech')
      ? { rejectUnauthorized: false }
      : undefined,
  });

  return globalThis.__pgPool;
}

/**
 * Proxy-based singleton: pool.connect() and all other Pool methods work
 * normally, but the underlying Pool is not created until first access.
 * This prevents module-import-time throws during `next build`.
 */
export const pool = new Proxy({} as Pool, {
  get(_target, prop) {
    const p = getPool();
    const val = (p as unknown as Record<string | symbol, unknown>)[prop];
    return typeof val === 'function' ? val.bind(p) : val;
  },
});

/**
 * Simple Anomaly Detection for Agent Spend
 */

import { prisma } from '@/lib/prisma';

export async function detectSpendAnomalies(organizationId: string) {
  const recentLogs = await prisma.tokenLog.findMany({
    where: {
      room: { organizationId },
      createdAt: { gte: new Date(Date.now() - 1000 * 60 * 60 * 4) }, // last 4 hours
    },
    orderBy: { createdAt: 'desc' },
    take: 200,
  });

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const anomalies: any[] = [];

  // Very simple heuristic: 5x average spend in last hour vs previous 3 hours
  const grouped = recentLogs.reduce((acc: Record<number, number>, log: any) => {
    const hour = Math.floor(new Date(log.createdAt).getTime() / (1000 * 60 * 60));
    if (!acc[hour]) acc[hour] = 0;
    acc[hour] += (log.cost_in_cents || 0);
    return acc;
  }, {} as Record<number, number>);

  const hours = Object.keys(grouped).map(Number).sort((a, b) => b - a);
  if (hours.length >= 2) {
    const latest = grouped[hours[0]];
    const previousAvg = hours.slice(1, 4).reduce((sum, h) => sum + (grouped[h] || 0), 0) / Math.max(1, hours.length - 1);

    if (latest > previousAvg * 5 && latest > 500) {
      anomalies.push({
        type: 'spend_spike',
        severity: 'high',
        message: `Unusual spend spike detected for organization (latest hour: $${(latest / 100).toFixed(2)})`,
        value: latest,
      });
    }
  }

  return anomalies;
}
